const a = [
  {"id":4760,"text":"Which of the following nerves supplies the dermatome that is involved in referring the pain from the appendix to the umbilical region?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 48.","responses":[{"text":"10th thoracic nerve","correct":true,"visible":false},{"text":"3rd cervical nerve","correct":false,"visible":false},{"text":"5th cranial nerve","correct":false,"visible":false},{"text":"7th thoracic nerve","correct":false,"visible":false},{"text":"4th thoracic nerve","correct":false,"visible":false}]},{"id":4812,"text":"Which of the following drugs is recommended for the quickest treatment for ulcers?","explanation":null,"reference":"1) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1093.\r\n\r\n2) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 543, 544.","responses":[{"text":"Omeprazole","correct":true,"visible":false},{"text":"H2 antagonists","correct":false,"visible":false},{"text":"Misoprostol","correct":false,"visible":false},{"text":"Antacid","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false}]},{"id":5467,"text":"The Rule of Nines is used for which of the following?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 268.","responses":[{"text":"Head trauma","correct":false,"visible":false},{"text":"Burns","correct":true,"visible":false},{"text":"Fractures","correct":false,"visible":false},{"text":"Electrical injury","correct":false,"visible":false},{"text":"Datura poisoning","correct":false,"visible":false}]},{"id":5759,"text":"Encephalopathy, wrist-drop, and constipation are the triad most commonly seen in which of the following toxicities?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 502.","responses":[{"text":"Phosphorous","correct":false,"visible":false},{"text":"Arsenic","correct":false,"visible":false},{"text":"Thallium","correct":false,"visible":false},{"text":"Mercury","correct":false,"visible":false},{"text":"Lead","correct":true,"visible":false}]},{"id":5799,"text":"Which of the following is characterized by recurrent aphthous ulcers?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 799.","responses":[{"text":"Celiac disease","correct":false,"visible":false},{"text":"Irritable bowel syndrome","correct":false,"visible":false},{"text":"Crohn's disease","correct":true,"visible":false},{"text":"Giardiasis","correct":false,"visible":false},{"text":"Ulcerative colitis","correct":false,"visible":false}]},{"id":5800,"text":"What is most commonly associated with a tumor in the head of the pancreas?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 407.","responses":[{"text":"Epigastric discomfort","correct":false,"visible":false},{"text":"Dark urine","correct":false,"visible":false},{"text":"Nausea and vomiting","correct":false,"visible":false},{"text":"Obstructive jaundice","correct":true,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false}]},{"id":5801,"text":"Which organ produces the most digestive enzymes?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 815.","responses":[{"text":"Liver","correct":false,"visible":false},{"text":"Pancreas","correct":true,"visible":false},{"text":"Small intestines","correct":false,"visible":false},{"text":"Stomach","correct":false,"visible":false},{"text":"Salivary glands","correct":false,"visible":false}]},{"id":5802,"text":"Which of the following is true regarding the pancreas?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 219.","responses":[{"text":"Its neck, body and tail develops from the ventral bud","correct":false,"visible":false},{"text":"It is mesodermal in origin","correct":false,"visible":false},{"text":"It is the embryonic derivative of foregut","correct":true,"visible":false},{"text":"Its uncinate process develops from the dorsal bud","correct":false,"visible":false},{"text":"It is ectodermal in origin","correct":false,"visible":false}]},{"id":5810,"text":"What is the most common cause of esophageal variceal bleeding?","explanation":null,"reference":null,"responses":[{"text":"Wilson disease","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Liver cirrhosis","correct":true,"visible":false},{"text":"Fatty liver","correct":false,"visible":false},{"text":"Schistosomiasis","correct":false,"visible":false}]},{"id":5812,"text":"Which of the following will be observed on endoscopic biopsy of celiac disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 783.","responses":[{"text":"Dysplasia","correct":false,"visible":false},{"text":"Aplasia","correct":false,"visible":false},{"text":"Villous atrophy","correct":true,"visible":false},{"text":"Metaplasia","correct":false,"visible":false},{"text":"Hyperplasia","correct":false,"visible":false}]},{"id":5813,"text":"Which of the following results from the first hit in the pathogenesis of colorectal carcinoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 811.","responses":[{"text":"Methylation instability","correct":false,"visible":false},{"text":"Chromosomal alteration","correct":false,"visible":false},{"text":"Germline and somatic mutations of tumor suppressor genes","correct":true,"visible":false},{"text":"Protooncogene mutation","correct":false,"visible":false},{"text":"Upregulation of COX 1","correct":false,"visible":false}]},{"id":5818,"text":"A 35-year-old female patient reports having epigastric abdominal pain for the last 7 months and has also lost 10 kg weight during this time. She is currently taking proton pump inhibitors (PPI). What is the next step in management?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 799.\r\n\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 767.","responses":[{"text":"Continue proton pump inhibitors (PPI)","correct":false,"visible":false},{"text":"Stool culture","correct":false,"visible":false},{"text":"Order an endoscopy","correct":true,"visible":false},{"text":"Stop all medication","correct":false,"visible":false},{"text":"Test for Helicobacter pylori","correct":false,"visible":false}]},{"id":5833,"text":"Which of the following is used to screen for colorectal carcinoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 807.","responses":[{"text":"X-ray","correct":false,"visible":false},{"text":"Complete blood count","correct":false,"visible":false},{"text":"Tumor markers assessment","correct":false,"visible":false},{"text":"Colonoscopy","correct":true,"visible":false},{"text":"Computerized tomography (CT) scan","correct":false,"visible":false}]},{"id":5837,"text":"A 37-year-old patient, on steroids for ulcerative colitis, is in sustained remission. He develops central obesity and a moon-like face. What is the next step in his management?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 970.","responses":[{"text":"Continue steroids for remission","correct":false,"visible":false},{"text":"Ileal resection","correct":false,"visible":false},{"text":"Proctocolectomy","correct":false,"visible":false},{"text":"Surgery","correct":false,"visible":false},{"text":"Treat Cushing’s syndrome","correct":true,"visible":false}]},{"id":5841,"text":"Which of the following is not a complication of acute liver failure?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 858.\r\n\r\n\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 826-827.","responses":[{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Renal failure","correct":false,"visible":false},{"text":"Hyperglycemia","correct":true,"visible":false},{"text":"Cerebral edema","correct":false,"visible":false},{"text":"Encephalopathy","correct":false,"visible":false}]},{"id":5843,"text":"Which disease does not cause cholestatic jaundice?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 860.\r\n\r\n2) Shah R, John S. Cholestatic jaundice. In: StatPearls. StatPearls Publishing; 2022. Accessed July 19, 2022. http://www.ncbi.nlm.nih.gov/books/NBK482279/","responses":[{"text":"Zellweger syndrome","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Hodgkin disease","correct":false,"visible":false},{"text":"Diabetes","correct":true,"visible":false},{"text":"Cystic fibrosis","correct":false,"visible":false}]},{"id":5844,"text":"Which of the following signs can help confirm appendicitis?","explanation":null,"reference":"Winterbottom, Christopher Toby. “Positive Psoas Sign in Presentation of Retroperitoneal Malignant Triton Tumour.” BMJ Case Reports, 5 Apr. 2010, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3047516/.","responses":[{"text":"Trousseau sign","correct":false,"visible":false},{"text":"Cullen’s sign","correct":false,"visible":false},{"text":"Grey Turner’s sign","correct":false,"visible":false},{"text":"Psoas sign","correct":true,"visible":false},{"text":"Troisier’s sign","correct":false,"visible":false}]},{"id":5845,"text":"A 21-year-old female presents to the emergency room in an unconscious state. On examination, she has a sweet-smelling odor. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1114.","responses":[{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Respiratory alklaosis","correct":false,"visible":false}]},{"id":5846,"text":"What is the most common site of diverticulitis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 803.","responses":[{"text":"Descending colon","correct":false,"visible":false},{"text":"Transverse colon","correct":false,"visible":false},{"text":"Rectum","correct":false,"visible":false},{"text":"Sigmoid colon","correct":true,"visible":false},{"text":"Ascending colon","correct":false,"visible":false}]},{"id":5847,"text":"A 38-year-old woman presents with weight loss, evening pyrexia, night sweats. On examination, she has a lump in the right quadrant. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 590, 812.","responses":[{"text":"Ulcerative colitis","correct":false,"visible":false},{"text":"Intestinal sarcoidosis","correct":false,"visible":false},{"text":"Intestinal tuberculosis","correct":true,"visible":false},{"text":"Colorectal carcinoma","correct":false,"visible":false},{"text":"Crohn disease","correct":false,"visible":false}]},{"id":5848,"text":"What is the most common site of Intestinal tuberculosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 812.","responses":[{"text":"1st part of the duodenum","correct":false,"visible":false},{"text":"2st part of the duodenum","correct":false,"visible":false},{"text":"Proximal ileum","correct":false,"visible":false},{"text":"Terminal ileum","correct":true,"visible":false},{"text":"3st part of the duodenum","correct":false,"visible":false}]},{"id":5849,"text":"Which of the following is a polypoid bulge of the mucosa of the large bowel that is present in ulcerative colitis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 800.","responses":[{"text":"Hyperplastic polyp","correct":false,"visible":false},{"text":"Aplastic polyp","correct":false,"visible":false},{"text":"Pseudopolyp","correct":true,"visible":false},{"text":"Inflammatory polyp","correct":false,"visible":false},{"text":"Adenomatous polyp","correct":false,"visible":false}]},{"id":5851,"text":"Which of the following parameters help differentiate between cholelithiasis and acute cholecystitis?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 904-905.\r\n\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 878.","responses":[{"text":"Platelet count","correct":false,"visible":false},{"text":"Leukocyte count","correct":true,"visible":false},{"text":"Epigastric pain","correct":false,"visible":false},{"text":"Erythrocyte count","correct":false,"visible":false},{"text":"Jaundice","correct":false,"visible":false}]},{"id":5852,"text":"Which of the following is a sign of localized peritonitis?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 787.\r\n\r\n(2) Patterson JW, Kashyap S, Dominique E. Acute abdomen. In: StatPearls. StatPearls Publishing; 2022. Accessed August 8, 2022. http://www.ncbi.nlm.nih.gov/books/NBK459328/","responses":[{"text":"Fever","correct":false,"visible":false},{"text":"Rebound tenderness on affected area","correct":true,"visible":false},{"text":"Irregular pulse","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Lack of abdominal movement during respiration","correct":false,"visible":false}]},{"id":5855,"text":"Which of the following is characterized by subtotal villous atrophy?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 783.","responses":[{"text":"Gastroenteritis","correct":false,"visible":false},{"text":"Ulcerative colitis","correct":false,"visible":false},{"text":"Irritable bowel syndrome","correct":false,"visible":false},{"text":"Crohn disease","correct":false,"visible":false},{"text":"Celiac disease","correct":true,"visible":false}]},{"id":5856,"text":"Parietal cell antibodies are present in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 763-764.","responses":[{"text":"Colorectal carcinoma","correct":false,"visible":false},{"text":"Ulcerative colitis","correct":false,"visible":false},{"text":"Acute gastritis","correct":false,"visible":false},{"text":"Chronic gastritis","correct":true,"visible":false},{"text":"Crohn disease","correct":false,"visible":false}]},{"id":5857,"text":"A 39-year-old female comes to the outpatient department with abdominal pain. She has a history of weight loss and jaundice. Labs reveal raised alpha-fetoprotein (AFP) and des-gamma-carboxyprothrombin (DCP) levels. What is the most likely diagnosis?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 873.\r\n\r\n2) Inagaki Y, Tang W, Makuuchi M, Hasegawa K, Sugawara Y, Kokudo N. Clinical and molecular insights into the hepatocellular carcinoma tumour marker des-γ-carboxyprothrombin. Liver International: Official Journal of the International Association for the Study of the Liver. Published January 2011. https://pubmed.ncbi.nlm.nih.gov/20874725/","responses":[{"text":"Hepatocellular carcinoma","correct":true,"visible":false},{"text":"Hepatic adenoma","correct":false,"visible":false},{"text":"Liver cirrhosis","correct":false,"visible":false},{"text":"Cholangiocarcinoma","correct":false,"visible":false},{"text":"Primary hepatic lymphoma","correct":false,"visible":false}]},{"id":5858,"text":"Adenocarcinoma is associated with which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 110.","responses":[{"text":"Gasrtoenteritis","correct":false,"visible":false},{"text":"Toxic megacolon","correct":false,"visible":false},{"text":"Intestinal tuberculosis","correct":false,"visible":false},{"text":"Ulcerative colitis","correct":true,"visible":false},{"text":"Celiac disease","correct":false,"visible":false}]},{"id":5859,"text":"What is the name of the sign in which right inferior quadrant (RIQ) pain is elicited by palpation of the left inferior quadrant (LIQ)?","explanation":null,"reference":"Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 106.","responses":[{"text":"McBurney's sign","correct":false,"visible":false},{"text":"Dunphy's sign","correct":false,"visible":false},{"text":"Obturator sign","correct":false,"visible":false},{"text":"Rovsing's sign","correct":true,"visible":false},{"text":"Psoas sign","correct":false,"visible":false}]},{"id":5862,"text":"Which of the following is associated with a low-fiber diet?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 811.","responses":[{"text":"Chronic gastritis","correct":false,"visible":false},{"text":"Ischemic bowel","correct":false,"visible":false},{"text":"Crohn’s disease","correct":false,"visible":false},{"text":"Colon carcinoma","correct":true,"visible":false},{"text":"Acute gastritis","correct":false,"visible":false}]},{"id":5943,"text":"Carcinoembryonic antigen (CEA) levels are raised in which of the following?","explanation":null,"reference":"Kankanala VL, Mukkamalla SKR. Carcinoembryonic antigen. In: StatPearls. StatPearls Publishing; 2022. Accessed August 2, 2022. http://www.ncbi.nlm.nih.gov/books/NBK578172/","responses":[{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Gastric adenocarcinoma","correct":false,"visible":false},{"text":"Esophageal squamous cell carcinoma","correct":false,"visible":false},{"text":"Metastatic colorectal cancer","correct":true,"visible":false},{"text":"Mucoepidermoid carcinoma","correct":false,"visible":false}]},{"id":5944,"text":"A man at a barbeque party starts vomiting profusely and continuously. He also complains of lower chest and upper abdominal pain, He is taken to the hospital. On examination, tenderness, tachycardia, and hypotension are observed. What is the most likely cause?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 754.\r\n\r\n(2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 387.","responses":[{"text":"Duodenal atresia","correct":false,"visible":false},{"text":"Enteric fever","correct":false,"visible":false},{"text":"Acute gastritis","correct":false,"visible":false},{"text":"Boerhaave syndrome","correct":true,"visible":false},{"text":"Acute pancreatitis","correct":false,"visible":false}]},{"id":5946,"text":"What is the most common site of colorectal carcinoma?","explanation":null,"reference":"William NS, O’Connell PR, McCaskie AW, eds. Bailey \u0026 Love’s Short Practice of Surgery. 27th ed. CRC Press, Taylor \u0026 Francis Group; 2018: 1328.","responses":[{"text":"Sigmoid colon","correct":false,"visible":false},{"text":"Ascending colon","correct":false,"visible":false},{"text":"Descending colon","correct":false,"visible":false},{"text":"Rectum","correct":true,"visible":false},{"text":"Ileocecal junction","correct":false,"visible":false}]},{"id":5950,"text":"A portocaval anastomosis does not lead to which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 829-830.","responses":[{"text":"Encephalopathy","correct":false,"visible":false},{"text":"Variceal bleeding","correct":false,"visible":false},{"text":"Ascites","correct":false,"visible":false},{"text":"Thrombosis","correct":true,"visible":false},{"text":"Hemorrhoids","correct":false,"visible":false}]},{"id":5957,"text":"Which of the following is correct regarding the tumors of the gall bladder?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 879-880.","responses":[{"text":"They occur more commonly in males","correct":false,"visible":false},{"text":"They usually metastasize to spine","correct":false,"visible":false},{"text":"Squamous cell type of the cancer is the most common","correct":false,"visible":false},{"text":"90% are diagnosed pre-operatively","correct":false,"visible":false},{"text":"Infiltrative form of gall bladder cancers is more common","correct":true,"visible":false}]},{"id":5959,"text":"Which of the following is a non-epithelioid gastric tumor?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 268, 773-774.","responses":[{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Papilloma","correct":false,"visible":false},{"text":"Gastric adenocarcinoma","correct":false,"visible":false},{"text":"Kaposi sarcoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":true,"visible":false}]},{"id":5962,"text":"A 3-month-old child has acute diarrhea and is irritable. When his skin is pinched it goes down slowly. His mucosal membranes are also seen to be dry. What is the appropriate treatment?","explanation":null,"reference":"(1) Diarrhoea and Dehydration. World Health Organization; 2008. Accessed August 2, 2022. https://www.ncbi.nlm.nih.gov/books/NBK143745/\r\n\r\n(2) Vega RM, Avva U. Pediatric dehydration. In: StatPearls. StatPearls Publishing; 2022. Accessed August 8, 2022. http://www.ncbi.nlm.nih.gov/books/NBK436022/","responses":[{"text":"Oral rehydration solution 300 ml every 4 hours","correct":true,"visible":false},{"text":"Normal saline","correct":false,"visible":false},{"text":"Ringers solution and metronidazole","correct":false,"visible":false},{"text":"Oral rehydration solution 50-60 mg after watery diarrhea","correct":false,"visible":false},{"text":"Dextrose solution and metronidazole","correct":false,"visible":false}]},{"id":5967,"text":"A 3-month-old child has acute diarrhea and is irritable. When his skin is pinched it goes down slowly. His mucosal membranes are also seen to be dry. Which of the following corresponds to the condition of this child?","explanation":null,"reference":"(1) Vega RM, Avva U. Pediatric dehydration. In: StatPearls. StatPearls Publishing; 2022. Accessed August 8, 2022. http://www.ncbi.nlm.nih.gov/books/NBK436022/\r\n\r\n(2) Clinical practice guidelines : dehydration. Accessed August 8, 2022. https://www.rch.org.au/clinicalguide/guideline_index/Dehydration/\r\n\r\n(3) Diarrhoea and Dehydration. World Health Organization; 2008. Accessed August 2, 2022. https://www.ncbi.nlm.nih.gov/books/NBK143745/","responses":[{"text":"The child is not dehydrated","correct":false,"visible":false},{"text":"Severe dehydration","correct":false,"visible":false},{"text":"Mild dehydration","correct":false,"visible":false},{"text":"Moderate dehydration","correct":true,"visible":false},{"text":"Hypovolemia","correct":false,"visible":false}]},{"id":5969,"text":"What is the most common cause of acute gastroenteritis in children less than 1 year in age?","explanation":null,"reference":"Rivera-Dominguez G, Ward R. Pediatric gastroenteritis. In: StatPearls. StatPearls Publishing; 2022. Accessed August 2, 2022. http://www.ncbi.nlm.nih.gov/books/NBK499939/","responses":[{"text":"Adenovirus","correct":false,"visible":false},{"text":"Shigella","correct":false,"visible":false},{"text":"Rotavirus","correct":true,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Salmonella","correct":false,"visible":false}]},{"id":5972,"text":"Which of the following conditions is characterized by profuse, non-bilious vomiting after feeding?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 751.","responses":[{"text":"Pyloric stenosis","correct":true,"visible":false},{"text":"Hirschsprung  disease","correct":false,"visible":false},{"text":"Necrotizing  enterocolitis","correct":false,"visible":false},{"text":"Duodenal atresia","correct":false,"visible":false},{"text":"Malrotation and volvulus","correct":false,"visible":false}]},{"id":5974,"text":"A 6-year-old child presents with lethargy, unconsciousness, and an acidotic breath. Which of the following tests would be appropriate in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1114.","responses":[{"text":"Chest X-ray","correct":false,"visible":false},{"text":"Blood sugar level","correct":true,"visible":false},{"text":"Renal function test","correct":false,"visible":false},{"text":"Complete blood count","correct":false,"visible":false},{"text":"Liver function test","correct":false,"visible":false}]},{"id":5977,"text":"A 10-year-old boy is brought to the emergency room with heavy breathing and convulsions. His blood sugar level is 400 mg/dL. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1114.","responses":[{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Salicylate toxicity","correct":false,"visible":false},{"text":"Respiratory distress syndrome","correct":false,"visible":false},{"text":"Hypokalemia","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false}]},{"id":5979,"text":"An infant presents with cherry-red spots on the macula. He has had progressive loss of developmental milestones and shows signs of mental retardation. Which of the following investigations should be done?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 152-154, 1337.\r\n\r\n(2) Ramani PK, Parayil Sankaran B. Tay-sachs disease. In: StatPearls. StatPearls Publishing; 2022. Accessed August 8, 2022. http://www.ncbi.nlm.nih.gov/books/NBK564432/","responses":[{"text":"Liver function test","correct":false,"visible":false},{"text":"Serum ammonia","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false},{"text":"Liver biopsy","correct":true,"visible":false},{"text":"Complete blood count","correct":false,"visible":false}]},{"id":5980,"text":"The 5-year-old child is having episodes of convulsions. On examination hepatosplenomegaly, and abdominal distention is observed. A blood sugar test reveals hypoglycemia. What is the most likely diagnosis?","explanation":null,"reference":"(1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 129-130.\r\n\r\n(2) Parikh NS, Ahlawat R. Glycogen storage disease type i. In: StatPearls. StatPearls Publishing; 2022. Accessed August 5, 2022. http://www.ncbi.nlm.nih.gov/books/NBK534196/","responses":[{"text":"Niemann pick disease","correct":false,"visible":false},{"text":"Hereditary galactokinase deficiency","correct":false,"visible":false},{"text":"Pompe disease","correct":false,"visible":false},{"text":"McArdle disease","correct":false,"visible":false},{"text":"Von Gierke disease","correct":true,"visible":false}]},{"id":5981,"text":"Which of the following is used in combination with adefovir dipivoxil to prevent resistance?","explanation":null,"reference":"(1) Ryu SH, Chung YH. [Resistance to adefovir in patients with chronic hepatitis B]. The Korean Journal of Hepatology. Published December 2006. https://pubmed.ncbi.nlm.nih.gov/17237626/\r\n\r\n\r\n(2) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 886.","responses":[{"text":"Ribavirin","correct":false,"visible":false},{"text":"Afavirenz","correct":false,"visible":false},{"text":"Emtricitabine","correct":false,"visible":false},{"text":"Abacavir","correct":false,"visible":false},{"text":"Lamivudine","correct":true,"visible":false}]},{"id":5982,"text":"What is the mechanism of action of adefovir dipivoxil?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 886.","responses":[{"text":"Guanosine analog","correct":false,"visible":false},{"text":"Cytidine analog","correct":false,"visible":false},{"text":"DNA polymerase Inhibitor","correct":true,"visible":false},{"text":"Nucleoside reverse transcriptase inhibitor (NRTI)","correct":false,"visible":false},{"text":"Nucleoside analog","correct":false,"visible":false}]},{"id":5985,"text":"Metoclopramide and domperidone are dopamine antagonists. Which of the following is not seen with domperidone?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1098.","responses":[{"text":"Diarrhea","correct":false,"visible":false},{"text":"Gynecomastia","correct":false,"visible":false},{"text":"Galactorrhea","correct":false,"visible":false},{"text":"Tardive dyskinesia","correct":true,"visible":false},{"text":"Impotence","correct":false,"visible":false}]},{"id":5986,"text":"Which of the following is deficient in a person taking proton-pump inhibitors?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1094.","responses":[{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin B12","correct":true,"visible":false},{"text":"Vitamin B6","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false}]},{"id":5987,"text":"Which of the following drugs is used for heartburn and lowers acid secretion by blocking H2 receptors?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1089-1090.","responses":[{"text":"Sucralfate","correct":false,"visible":false},{"text":"Octreotide","correct":false,"visible":false},{"text":"Cimetidine","correct":true,"visible":false},{"text":"Omeprazole","correct":false,"visible":false},{"text":"Misoprostol","correct":false,"visible":false}]},{"id":5988,"text":"Patients being given cimetidine should be warned regarding which of the following?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1091.","responses":[{"text":"Gynecomastia","correct":true,"visible":false},{"text":"Increased libido","correct":false,"visible":false},{"text":"Constipation","correct":false,"visible":false},{"text":"Diarrhea","correct":false,"visible":false},{"text":"Hypokalemia","correct":false,"visible":false}]},{"id":5989,"text":"Which of the following drugs prevents acid secretion by irreversibly binding to H+/K+ ATPase receptors?","explanation":"**Omeprazole** and other proton pump inhibitors (PPIs) work by **irreversibly** inhibiting the **H+/K+ ATPase proton pump** (also known as the gastric proton pump) in the stomach's parietal cells. This pump is responsible for the final step in the production of gastric acid. By binding to and inhibiting this pump, omeprazole reduces the production of stomach acid, making it effective in treating conditions associated with excess stomach acid, such as gastroesophageal reflux disease (GERD) and peptic ulcers.","reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1091-1092.","responses":[{"text":"Misoprostol","correct":false,"visible":false},{"text":"Aluminium hydroxide","correct":false,"visible":false},{"text":"Nizatidine","correct":false,"visible":false},{"text":"Omeprazole","correct":true,"visible":false},{"text":"Octreotide","correct":false,"visible":false}]},{"id":5990,"text":"What is the correct mechanism of action of methylxanthines?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 194.","responses":[{"text":"Negative chronotropic and inotropic effects","correct":false,"visible":false},{"text":"Increased gastric acid secretion","correct":true,"visible":false},{"text":"Central nervous system depression","correct":false,"visible":false},{"text":"Urinary retention","correct":false,"visible":false},{"text":"Increased bronchoconstriction","correct":false,"visible":false}]},{"id":5991,"text":"What is the first-line treatment of acute variceal bleeding?","explanation":null,"reference":"(1) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 1114.\r\n\r\n\r\n(2) Kim YD. Management of acute variceal bleeding. Clinical Endoscopy. Published July 2014. Accessed August 5, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4130884/","responses":[{"text":"Subcutaneous octreotide","correct":false,"visible":false},{"text":"Blood transfusion","correct":false,"visible":false},{"text":"Secondary prophylaxis","correct":false,"visible":false},{"text":"Intravenous terlipressin","correct":true,"visible":false},{"text":"Broad-spectrum antibiotics","correct":false,"visible":false}]},{"id":5993,"text":"Which of the following is used to treat a Helicobacter pylori infection?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1093.","responses":[{"text":"Erythromycin","correct":false,"visible":false},{"text":"Clarithromycin","correct":true,"visible":false},{"text":"Ciprofloxacin","correct":false,"visible":false},{"text":"Penicillin","correct":false,"visible":false},{"text":"Trimethoprim","correct":false,"visible":false}]},{"id":6071,"text":"What is the route of transmission of the hepatitis E virus (HEV)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 119.","responses":[{"text":"Perinatal route","correct":false,"visible":false},{"text":"Fecal-oral route","correct":true,"visible":false},{"text":"Parenteral route","correct":false,"visible":false},{"text":"Blood-borne route","correct":false,"visible":false},{"text":"Sexual route","correct":false,"visible":false}]},{"id":6072,"text":"A 37-year-old male patient is being tested. His reports show HBsAg=-ve, anti-HBs=-ve, anti-HBe=-ve, HBeAg=-ve, and anti-HBc=IgM reactive. Which of the following corresponds to this patient's results?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 833.\r\n\r\n\r\n(2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 120.","responses":[{"text":"Recovery from hepatitis","correct":false,"visible":false},{"text":"Incubatory period","correct":false,"visible":false},{"text":"Vaccination","correct":false,"visible":false},{"text":"Acute hepatitis B","correct":true,"visible":false},{"text":"Chronic with low virulence","correct":false,"visible":false}]},{"id":6073,"text":"Which of the following organisms causes enterocolitis associated with Reiter’s syndrome?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 155.","responses":[{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Shigella dysenteriae","correct":false,"visible":false},{"text":"Vibrio cholerae","correct":false,"visible":false},{"text":"Salmonella typhi","correct":false,"visible":false},{"text":"Campylobacter jejuni","correct":true,"visible":false}]},{"id":6074,"text":"Which of the following is a spiral-shaped organism?","explanation":null,"reference":"(1) Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 156.\r\n\r\n\r\n\r\n(2) Krzyżek P, Gościniak G. Morphology of Helicobacter pylori as a result of peptidoglycan and cytoskeleton rearrangements. Przegla̜d Gastroenterologiczny. Published 2018. Accessed August 5, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6173076/","responses":[{"text":"Bacillus anthracis","correct":false,"visible":false},{"text":"Streptococcus pyogenes","correct":false,"visible":false},{"text":"Sarcina ventriculi","correct":false,"visible":false},{"text":"Clostridium botulinum","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":true,"visible":false}]},{"id":6075,"text":"What is the incubation period of the hepatitis A virus?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 831.","responses":[{"text":"8 weeks","correct":false,"visible":false},{"text":"14 days","correct":false,"visible":false},{"text":"6 days","correct":false,"visible":false},{"text":"6 weeks","correct":true,"visible":false},{"text":"4 weeks","correct":false,"visible":false}]},{"id":6076,"text":"The endoscopy of a patient reveals an ulcerated mass on the antrum. A biopsy sample is sent and confirmed to be an adenocarcinoma. What is the most appropriate treatment?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 804.","responses":[{"text":"Total gastrectomy","correct":false,"visible":false},{"text":"Subtotal gastrectomy","correct":true,"visible":false},{"text":"Drainage","correct":false,"visible":false},{"text":"Radical gastrectomy","correct":false,"visible":false},{"text":"Wedge resection","correct":false,"visible":false}]},{"id":6077,"text":"Which of the following is the appropriate intervention for a peptic ulcer with duodenal perforation?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 801.\r\n\r\n(2) Wang YL, Chan XW, Chan KS, Shelat VG. Omental patch repair of large perforated peptic ulcers ≥25 mm is associated with higher leak rate. J Clin Transl Res. 2021;7(6):759-766. Accessed August 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8710357/","responses":[{"text":"Sleeve gastrectomy","correct":false,"visible":false},{"text":"Reichel–Polya operation","correct":false,"visible":false},{"text":"Bilroth II","correct":false,"visible":false},{"text":"Keep omental patch and suture the defect","correct":true,"visible":false},{"text":"Bilroth I","correct":false,"visible":false}]},{"id":6079,"text":"What causes post-operative paralytic ileus?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 361.\r\n\r\n(2) Beach EC, De Jesus O. Ileus. In: StatPearls. StatPearls Publishing; 2022. Accessed August 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK558937/","responses":[{"text":"Hypokalemia","correct":true,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Uremia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false}]},{"id":6080,"text":"Saturated fatty acids increase the risk of which of the following diseases?","explanation":null,"reference":"Briggs MA, Petersen KS, Kris-Etherton PM. Saturated fatty acids and cardiovascular disease: replacements for saturated fat to reduce cardiovascular risk. Healthcare (Basel, Switzerland). Published June 21, 2017. https://pubmed.ncbi.nlm.nih.gov/28635680/","responses":[{"text":"Cardiovascular disease","correct":true,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false},{"text":"Duodenal ulcers","correct":false,"visible":false},{"text":"Steatorrhea","correct":false,"visible":false},{"text":"Gastric carcinoma","correct":false,"visible":false}]},{"id":6081,"text":"Which of the following correctly describes the glycemic index?","explanation":"The **glycemic index (GI)** is defined as the **ability of food to increase blood glucose levels** when compared to a reference carbohydrate, typically glucose or white bread. Foods with a high GI are rapidly digested and absorbed, leading to a quicker and larger increase in blood glucose levels, while foods with a low GI are digested and absorbed more slowly, resulting in a slower and smaller increase in blood glucose levels.","reference":"(1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 366.\r\n\r\n\r\n(2) Vlachos D, Malisova S, Lindberg FA, Karaniki G. Glycemic index (Gi) or glycemic load (Gl) and dietary interventions for optimizing postprandial hyperglycemia in patients with t2 diabetes: a review. Nutrients. Published May 27, 2020. Accessed August 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7352659/","responses":[{"text":"The ability of food to increase blood glucose levels","correct":true,"visible":false},{"text":"The ability of food to reduce blood glucose levels","correct":false,"visible":false},{"text":"The ability of the liver to reduce blood glucose levels","correct":false,"visible":false},{"text":"The ability of the liver to maintain blood glucose levels","correct":false,"visible":false},{"text":"The ability of the liver to increase blood glucose levels","correct":false,"visible":false}]},{"id":6083,"text":"Which of the following correctly describes the purpose of nutritional assessment?","explanation":null,"reference":"Kesari A, Noel JY. Nutritional assessment. In: StatPearls. StatPearls Publishing; 2022. Accessed August 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK580496/","responses":[{"text":"To assess the ratio of malnourished people","correct":true,"visible":false},{"text":"To assess the disease burden in a population","correct":false,"visible":false},{"text":"To assess the ratio of obese people","correct":false,"visible":false},{"text":"To assess the ratio of anemic people","correct":false,"visible":false},{"text":"To assess the ratio of economically disadvantaged people","correct":false,"visible":false}]},{"id":6098,"text":"Which of the following is a characteristic X-ray finding of jejunal obstruction?","explanation":null,"reference":"William NS, O’Connell PR, McCaskie AW, eds. Bailey \u0026 Love’s Short Practice of Surgery. 27th ed. CRC Press, Taylor \u0026 Francis Group; 2018: 80, 1288.","responses":[{"text":"Air under diaphragm","correct":false,"visible":false},{"text":"Valvulae conniventes","correct":true,"visible":false},{"text":"Thumbprinting sign","correct":false,"visible":false},{"text":"String of pearl appearance","correct":false,"visible":false},{"text":"Stepladder sign","correct":false,"visible":false}]},{"id":6099,"text":"Which of the following represents the distribution of sex and age of a population?","explanation":null,"reference":"GIT and liver-II module; Community-medicine lecture slides; Topic: Population pyramid.","responses":[{"text":"Population growth","correct":false,"visible":false},{"text":"Population dynamic","correct":false,"visible":false},{"text":"Population momentum","correct":false,"visible":false},{"text":"Population pyramid","correct":true,"visible":false},{"text":"Population distribution","correct":false,"visible":false}]},{"id":6100,"text":"Which of the following terms describes why population growth does not stop even after the fertility rate declines?","explanation":null,"reference":"GIT and liver-II module; Community-medicine lecture slides; Topic: Demography; Sub-topic: Population momentum.","responses":[{"text":"Population dynamics","correct":false,"visible":false},{"text":"Population distribution","correct":false,"visible":false},{"text":"Population momentum","correct":true,"visible":false},{"text":"Population pyramid","correct":false,"visible":false},{"text":"Population growth","correct":false,"visible":false}]},{"id":6101,"text":"Raindrop pigmentation and hyperkeratosis are characteristic findings of which poison?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 492.","responses":[{"text":"Lead","correct":false,"visible":false},{"text":"Arsenic","correct":true,"visible":false},{"text":"Zinc","correct":false,"visible":false},{"text":"Mercury","correct":false,"visible":false},{"text":"Copper","correct":false,"visible":false}]},{"id":6111,"text":"Hemorrhagic gastroenteritis, acute tubular necrosis, and shock are seen in which of the following toxicities?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 495-496.","responses":[{"text":"Thallium","correct":false,"visible":false},{"text":"Lead","correct":false,"visible":false},{"text":"Arsenic","correct":false,"visible":false},{"text":"Phosphorus","correct":false,"visible":false},{"text":"Mercury","correct":true,"visible":false}]},{"id":6114,"text":"A road rash is classified as which type of injury?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 189.","responses":[{"text":"Scratch abrasion","correct":false,"visible":false},{"text":"Imprint abrasion","correct":false,"visible":false},{"text":"Pressure abrasion","correct":false,"visible":false},{"text":"Graze abrasion","correct":true,"visible":false},{"text":"Linear abrasion","correct":false,"visible":false}]},{"id":6115,"text":"A friction burn is which type of injury?","explanation":"A **friction burn** is considered an **abrasion**. It is a type of injury that occurs when the skin is rubbed or scraped against a rough surface, causing damage to the outer layer of the skin. Abrasions are often superficial and result in the removal of the skin's topmost layer.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 189-190.","responses":[{"text":"Chop wound","correct":false,"visible":false},{"text":"Contusion","correct":false,"visible":false},{"text":"Laceration","correct":false,"visible":false},{"text":"Abrasion","correct":true,"visible":false},{"text":"Slash wound","correct":false,"visible":false}]},{"id":6117,"text":"Which of the following terms measures a woman's physiological ability to bear and deliver children?","explanation":null,"reference":"GIT and liver-II module; Community-medicine lecture slides; Topic: Measures of fertility and mortality; Sub-topic: Concept of fecundity and fertility.","responses":[{"text":"Total fertility","correct":false,"visible":false},{"text":"Fecundity","correct":true,"visible":false},{"text":"Infertility","correct":false,"visible":false},{"text":"Fertility","correct":false,"visible":false},{"text":"Subfertility","correct":false,"visible":false}]},{"id":6121,"text":"Which of the following is a chemical asphyxiant?","explanation":"**Carbon monoxide gas** is a chemical **asphyxiant**. It interferes with the body's ability to transport oxygen in the blood, leading to oxygen deprivation in the body's tissues and organs. Carbon monoxide poisoning can be life-threatening. The other gases mentioned, such as mustard gas, nitric oxide gas, phosgene gas, and nitrogen dioxide gas, have toxic effects but do not primarily act as chemical asphyxiants.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 586.","responses":[{"text":"Nitric oxide gas","correct":false,"visible":false},{"text":"Carbon monoxide gas","correct":true,"visible":false},{"text":"Nitrogen dioxide gas","correct":false,"visible":false},{"text":"Mustard gas","correct":false,"visible":false},{"text":"Phosgene gas","correct":false,"visible":false}]},{"id":6126,"text":"Which of the following is a convex-shaped hemorrhage when seen on brain imaging?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 186.","responses":[{"text":"Intraparenchymal hemorrhage","correct":false,"visible":false},{"text":"Subarachnoid hemorrhage","correct":false,"visible":false},{"text":"Subdural hemorrhage","correct":false,"visible":false},{"text":"Intracerebral hemorrhage","correct":false,"visible":false},{"text":"Extradural hemorrhage","correct":true,"visible":false}]},{"id":6127,"text":"Pugilistic attitude is due to which of the following?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 270.","responses":[{"text":"Self defense","correct":false,"visible":false},{"text":"Tissue decomposition","correct":false,"visible":false},{"text":"Rigor mortis","correct":false,"visible":false},{"text":"Coagulation of muscle proteins","correct":true,"visible":false},{"text":"Livor mortis","correct":false,"visible":false}]},{"id":6128,"text":"Which of the following is the surest sign of death from starvation?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 209.","responses":[{"text":"Intestinal epithelial dysplasia","correct":false,"visible":false},{"text":"Distended gallbladder","correct":false,"visible":false},{"text":"Atrophied liver","correct":false,"visible":false},{"text":"Marked emaciation","correct":false,"visible":false},{"text":"Tissue paper intestine","correct":true,"visible":false}]},{"id":6129,"text":"Which of the following terms is used for a state of extreme emaciation?","explanation":null,"reference":"(1) Titi-Lartey OA, Gupta V. Marasmus. In: StatPearls. StatPearls Publishing; 2022. Accessed August 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK559224/\r\n\r\n\r\n(2) Benjamin O, Lappin SL. Kwashiorkor. In: StatPearls. StatPearls Publishing; 2022. Accessed August 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK507876/","responses":[{"text":"Malnutrition","correct":false,"visible":false},{"text":"Malabsorption","correct":false,"visible":false},{"text":"Kwashiorkor","correct":false,"visible":false},{"text":"Marasmus","correct":true,"visible":false},{"text":"Muscle wasting","correct":false,"visible":false}]},{"id":6130,"text":"What color precipitate is formed after adding 3% tannic acid to blood samples containing carboxyhemoglobin?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 681.","responses":[{"text":"Purple","correct":false,"visible":false},{"text":"Pink","correct":true,"visible":false},{"text":"White","correct":false,"visible":false},{"text":"Black","correct":false,"visible":false},{"text":"Cherry red","correct":false,"visible":false}]},{"id":6132,"text":"Which of the following is a sign of death that occurred due to antemortem burns?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 273.","responses":[{"text":"Peeling of skin","correct":false,"visible":false},{"text":"Pugilistic attitude","correct":false,"visible":false},{"text":"Crocodile-skin","correct":false,"visible":false},{"text":"Degloving sign","correct":false,"visible":false},{"text":"Carboxyhemoglobin presence","correct":true,"visible":false}]},{"id":6134,"text":"Which of the following is the correct color and its respective duration in a black eye?","explanation":null,"reference":"Vij K. Textbook of Forensic Medicine and Toxicology Principles and Practice. 5th ed. Elsevier; 2011: 219.","responses":[{"text":"Livid red 3rd day","correct":false,"visible":false},{"text":"Green 2nd day","correct":false,"visible":false},{"text":"Blue-black 2nd day","correct":false,"visible":false},{"text":"Violet 5th day","correct":false,"visible":false},{"text":"Red 1st day","correct":true,"visible":false}]},{"id":15166,"text":"Which of the following is the most common cause of infections post-splenectomy?","explanation":"***Streptococcus pneumoniae*** is the most common pathogen responsible for **post-splenectomy infections** due to the spleen's role in filtering bacteria and mounting an immune response to **encapsulated organisms**.\r\n\r\nVaccination against *S. pneumoniae*, along with *Neisseria meningitidis* and *Haemophilus influenzae* type b (Hib), is recommended for splenectomy patients to reduce the risk of overwhelming post-splenectomy infection (OPSI).\r\n\r\n***\r\n\r\n*N. meningitidis* and *H. influenzae* are also significant concerns post-splenectomy, but *S. pneumoniae* is the most common and concerning due to its prevalence and potential severity of infection.\r\n\r\nStaphylococcus aureus can cause infections in post-splenectomy patients, but it is not as common compared to the risks posed by encapsulated organisms like *S. pneumoniae*.","reference":"Tahir F, Ahmed J, Malik F. Post-splenectomy sepsis: a review of the literature. Cureus. Accessed January 26, 2023.\r\nhttps://www.ncbi.nlm.nih.gov/pmc/articles/PMC7059871/","responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Haemophilus influenza","correct":false,"visible":false},{"text":"Neisseria meningitidis","correct":false,"visible":false}]}
]

